def gen(rng, size):
    n = max(1, size)
    m = max(1, size // 2)
    def random_tree(sz):
        if sz == 1:
            return []
        edges = []
        for i in range(1, sz):
            parent = rng.randint(0, i - 1)
            edges.append([parent, i])
        return edges
    return [random_tree(n), random_tree(m)]

