class Solution:
    def minimumDiameterAfterMerge(self, edges1, edges2) -> int:
        from collections import deque
        def build_adj(edges, n):
            adj = [[] for _ in range(n)]
            for u, v in edges:
                adj[u].append(v)
                adj[v].append(u)
            return adj
        def bfs_farthest(adj, start):
            n = len(adj)
            dist = [-1] * n
            dist[start] = 0
            q = deque([start])
            far = start
            while q:
                u = q.popleft()
                for v in adj[u]:
                    if dist[v] == -1:
                        dist[v] = dist[u] + 1
                        if dist[v] > dist[far]:
                            far = v
                        q.append(v)
            return far, dist[far]
        def tree_diameter(edges, n):
            if n == 1:
                return 0
            adj = build_adj(edges, n)
            far1, _ = bfs_farthest(adj, 0)
            far2, d = bfs_farthest(adj, far1)
            return d
        n1 = len(edges1) + 1
        n2 = len(edges2) + 1
        d1 = tree_diameter(edges1, n1)
        d2 = tree_diameter(edges2, n2)
        merged = (d1 + 1) // 2 + 1 + (d2 + 1) // 2
        return max(d1, d2, merged)

