class Solution:
    def minimumDiameterAfterMerge(self, edges1, edges2) -> int:
        from collections import deque
        def diameter(edges):
            n = len(edges) + 1
            if n == 1:
                return 0
            adj = [[] for _ in range(n)]
            for u, v in edges:
                adj[u].append(v)
                adj[v].append(u)
            def bfs(s):
                dist = [-1] * n
                dist[s] = 0
                q = deque([s])
                far = s
                while q:
                    u = q.popleft()
                    for v in adj[u]:
                        if dist[v] < 0:
                            dist[v] = dist[u] + 1
                            if dist[v] > dist[far]: far = v
                            q.append(v)
                return far, dist[far]
            f, _ = bfs(0)
            _, d = bfs(f)
            return d
        d1, d2 = diameter(edges1), diameter(edges2)
        return max(d1, d2, (d1 + 1) // 2 + 1 + (d2 + 1) // 2)

